import{_ as n,o as a,c as t,e}from"./app-d7dec363.js";const c={};function p(i,s){return a(),t("div",null,s[0]||(s[0]=[e(`<h2 id="html-中的-javascript" tabindex="-1"><a class="header-anchor" href="#html-中的-javascript" aria-hidden="true">#</a> HTML 中的 JavaScript</h2><div class="custom-container tip"><p class="custom-container-title">小结</p><p><strong>1. script 元素有哪些属性？</strong></p><p>async、defer、type、src、crossorigin、integrity</p><p><strong>2. noscript</strong></p><p>当浏览器不支持脚本或禁用脚本时，noscript 元素会显示出来</p></div><h3 id="script" tabindex="-1"><a class="header-anchor" href="#script" aria-hidden="true">#</a> script</h3><p><code>&lt;script&gt;</code> 元素有以下属性：</p><ul><li>async：表示立即下载脚本，但不妨碍页面中的其他操作，比如下载其他资源或等待加载其他脚本，只对外部脚本文件有效</li><li>defer：表示脚本可以延迟到文档完全被解析和显示之后再执行，只对外部脚本文件有效</li><li>src：表示包含要执行代码的外部文件</li><li>type：表示代码块中脚本语言的内容类型（MIME 类型），如果这个值是 module，则代码会被当成 ES6 模块，而且只有这时候代码中才能出现 import 和 export 关键字</li><li>crossorigin：配置相关请求的 CORS（跨源资源共享）设置。默认不使用 CORS，也就是说，如果请求的资源不是同源的，那么将会忽略这个属性。如果设置了这个属性，那么请求会包含 Origin 头部信息，如果服务器认为这个请求是合法的，那么响应会包含 Access-Control-Allow-Origin 头部信息。这个属性的可用值如下： <ul><li>anonymous：发送请求时不会提供凭据信息（比如 cookie 等），也就是说，不会把当前域的 cookie 发送给目标请求</li><li>use-credentials：发送请求时会提供凭据信息（比如 cookie 等），也就是说，会把当前域的 cookie 发送给目标请求</li></ul></li><li>integrity：允许比对接收到的资源和指定的加密签名以验证子资源完整性（SRI，Subresource Integrity）。如果接受到的资源与这个属性指定的签名不匹配，则页面会报错，脚本不会执行。这个属性用于确保内容分发网络（CDN，Content Delivery Network）不会提供恶意内容</li></ul><p>使用 <code>&lt;script&gt;</code> 的方式有两种：</p><ol><li>直接在页面中嵌入行内 JavaScript 代码</li></ol><div class="language-html line-numbers-mode" data-ext="html"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>script</span><span class="token punctuation">&gt;</span></span><span class="token script"><span class="token language-javascript">
	<span class="token keyword">function</span> <span class="token function">sayScript</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// 出现字符串 </span></span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span> 时，需要转义
		console.log(&#39;&lt;\\/script&gt;&#39;)
	}
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="highlight-lines"><br><br><br><div class="highlight-line"> </div><br><br></div><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="2"><li>通过 src 属性包含外部 JavaScript 文件</li></ol><p>注：使用了 src 属性的 <code>&lt;script&gt;</code> 元素不应该在其 <code>&lt;script&gt;</code> 和 <code>&lt;/script&gt;</code> 标签之间再包含额外的 JavaScript 代码，否则会忽略这些额外的代码</p><h4 id="标签位置" tabindex="-1"><a class="header-anchor" href="#标签位置" aria-hidden="true">#</a> 标签位置</h4><ol><li>放在页面的 <code>&lt;head&gt;</code> 元素中</li><li>放在页面的 <code>&lt;body&gt;</code> 元素中的页面内容后面</li></ol><h4 id="推迟执行脚本" tabindex="-1"><a class="header-anchor" href="#推迟执行脚本" aria-hidden="true">#</a> 推迟执行脚本</h4><p>在 <code>&lt;script&gt;</code> 元素中设置 defer 属性（只适用于外部脚本），告诉浏览器立即下载，但延迟执行（解析到 <code>&lt;/html&gt;</code> 后）</p><blockquote><p>HTML5 规范要求脚本按照它们出现的先后顺序执行，因此第一个延迟脚本会先于第二个延迟脚本执行，而这两个脚本会先于 DOMContentLoaded 事件执行。但是延迟脚本不一定会按照顺序执行，也不一定会在 DOMContentLoaded 事件触发前执行，因此最好只包含一个延迟脚本</p></blockquote><h4 id="异步执行脚本" tabindex="-1"><a class="header-anchor" href="#异步执行脚本" aria-hidden="true">#</a> 异步执行脚本</h4><p>在 <code>&lt;script&gt;</code> 元素中设置 async 属性（只适用于外部脚本），告诉浏览器立即下载，与 defer 的区别是，异步脚本不保证按照它们的先后顺序执行</p><blockquote><p>给脚本添加 async 属性的目的是告诉浏览器，不必等待其他脚本，也不必阻塞文档呈现，立即下载并执行脚本。从这个意义上讲，标记为 async 的脚本不应该在加载期间修改 DOM。异步脚本一定会在页面的 load 事件前执行，但可能会在 DOMContentLoaded 事件触发之前或之后执行</p></blockquote><h4 id="动态加载脚本" tabindex="-1"><a class="header-anchor" href="#动态加载脚本" aria-hidden="true">#</a> 动态加载脚本</h4><p>通过向 DOM 中动态添加 <code>&lt;script&gt;</code> 元素加载指定的脚本</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> script <span class="token operator">=</span> document<span class="token punctuation">.</span><span class="token function">createElement</span><span class="token punctuation">(</span><span class="token string">&#39;script&#39;</span><span class="token punctuation">)</span>
script<span class="token punctuation">.</span>src <span class="token operator">=</span> <span class="token string">&#39;gibberish.js&#39;</span>
document<span class="token punctuation">.</span>head<span class="token punctuation">.</span><span class="token function">appendChild</span><span class="token punctuation">(</span>script<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>默认情况下，动态添加的脚本是异步执行的（相当于 async 为 true）</p><p>因为所有浏览器都支持 createElement() 方法，但不是所有浏览器都支持 async 属性，因此如果要统一动态脚本的加载行为，可以明确将其设置为同步加载：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> script <span class="token operator">=</span> document<span class="token punctuation">.</span><span class="token function">createElement</span><span class="token punctuation">(</span><span class="token string">&#39;script&#39;</span><span class="token punctuation">)</span>
script<span class="token punctuation">.</span>src <span class="token operator">=</span> <span class="token string">&#39;gibberish.js&#39;</span>
script<span class="token punctuation">.</span>async <span class="token operator">=</span> <span class="token boolean">false</span>
document<span class="token punctuation">.</span>head<span class="token punctuation">.</span><span class="token function">appendChild</span><span class="token punctuation">(</span>script<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>以这种方式获取的资源对浏览器预加载器是不可见的，严重影响它们在资源获取队列中的优先级，可能会影响性能</p><p>要想让预加载器知道这些动态请求文件的存在，可以在文档头部显示生声明它们：</p><div class="language-html line-numbers-mode" data-ext="html"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>link</span> <span class="token attr-name">rel</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>preload<span class="token punctuation">&quot;</span></span> <span class="token attr-name">href</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>gibberish.js<span class="token punctuation">&quot;</span></span> <span class="token punctuation">/&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="noscript" tabindex="-1"><a class="header-anchor" href="#noscript" aria-hidden="true">#</a> noscript</h3><p><code>&lt;noscript&gt;</code> 元素可以包含任何可以出现在 <code>&lt;body&gt;</code> 元素中的 HTML 元素，它的作用是提供替代内容，只有以下情况下才会显示：</p><ul><li>浏览器不支持脚本</li><li>浏览器对脚本的支持被关闭</li></ul>`,30)]))}const l=n(c,[["render",p],["__file","02.html.vue"]]);export{l as default};
